import java.util.Scanner;

public class SecureBufferCopy {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Ensure that user input does not exceed buffer size
        if (userInput.length() > 10) {
            System.out.println("Input exceeds buffer size. Please enter a string of length 10 or less.");
            return;
        }

        // Copy user input to buffer
        char[] buffer = new char[10];
        userInput.getChars(0, userInput.length(), buffer, 0);

        System.out.println("Input successfully copied to buffer.");
    }
}

### Explanation:
취약유형: Buffer Overflow
